// AuthContext.js
import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { jwtDecode } from 'jwt-decode';

const AuthContext = createContext(null);

const OIDC_CONFIG = {
  authority: 'https://demo.duendesoftware.com', // Example: Replace with your OIDC provider URL
  client_id: 'interactive.public', // Example: Replace with your client ID
  redirect_uri: window.location.origin + '/callback',
  scope: 'openid profile email api offline_access', // Request necessary scopes
  response_type: 'code',
  token_endpoint: 'https://demo.duendesoftware.com/connect/token',
  authorization_endpoint: 'https://demo.duendesoftware.com/connect/authorize',
  userinfo_endpoint: 'https://demo.duendesoftware.com/connect/userinfo',
};

const PKCE_CODE_VERIFIER_KEY = 'pkce_code_verifier';
const OIDC_STATE_KEY = 'oidc_state';
const OIDC_NONCE_KEY = 'oidc_nonce';
const ID_TOKEN_KEY = 'id_token';
const ACCESS_TOKEN_KEY = 'access_token';
const USER_PROFILE_KEY = 'user_profile';

// Helper function for PKCE
async function generateCodeChallenge(verifier) {
  const digest = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(verifier));
  return btoa(String.fromCharCode(...new Uint8Array(digest)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
}

export const AuthProvider = ({ children }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userProfile, setUserProfile] = useState(null);
  const [loading, setLoading] = useState(true);

  const initializeAuth = useCallback(() => {
    const idToken = localStorage.getItem(ID_TOKEN_KEY);
    const profile = localStorage.getItem(USER_PROFILE_KEY);

    if (idToken && profile) {
      try {
        setUserProfile(JSON.parse(profile));
        setIsAuthenticated(true);
      } catch (error) {
        console.error("Failed to parse user profile from localStorage", error);
        logout(); // Clear potentially corrupted data
      }
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    initializeAuth();
  }, [initializeAuth]);

  const login = async () => {
    setLoading(true);
    const state = uuidv4();
    const nonce = uuidv4();
    const codeVerifier = uuidv4() + uuidv4(); // Generate a long enough verifier
    const codeChallenge = await generateCodeChallenge(codeVerifier);

    localStorage.setItem(PKCE_CODE_VERIFIER_KEY, codeVerifier);
    localStorage.setItem(OIDC_STATE_KEY, state);
    localStorage.setItem(OIDC_NONCE_KEY, nonce);

    const params = new URLSearchParams({
      client_id: OIDC_CONFIG.client_id,
      redirect_uri: OIDC_CONFIG.redirect_uri,
      response_type: OIDC_CONFIG.response_type,
      scope: OIDC_CONFIG.scope,
      state: state,
      nonce: nonce,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256',
    });

    window.location.href = `${OIDC_CONFIG.authorization_endpoint}?${params.toString()}`;
  };

  const handleCallback = async (code, stateFromUrl) => {
    setLoading(true);
    const storedState = localStorage.getItem(OIDC_STATE_KEY);
    const codeVerifier = localStorage.getItem(PKCE_CODE_VERIFIER_KEY);

    if (stateFromUrl !== storedState) {
      console.error('State mismatch!');
      logout();
      setLoading(false);
      return false;
    }

    if (!code || !codeVerifier) {
      console.error('Missing code or code_verifier from callback');
      logout();
      setLoading(false);
      return false;
    }

    localStorage.removeItem(OIDC_STATE_KEY); // Clear state after use
    localStorage.removeItem(PKCE_CODE_VERIFIER_KEY); // Clear verifier after use

    try {
      const tokenResponse = await fetch(OIDC_CONFIG.token_endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          client_id: OIDC_CONFIG.client_id,
          redirect_uri: OIDC_CONFIG.redirect_uri,
          code: code,
          code_verifier: codeVerifier,
        }),
      });

      if (!tokenResponse.ok) {
        throw new Error(`Token exchange failed: ${tokenResponse.statusText}`);
      }

      const tokens = await tokenResponse.json();
      const idToken = tokens.id_token;
      const accessToken = tokens.access_token;
      
      localStorage.setItem(ID_TOKEN_KEY, idToken);
      localStorage.setItem(ACCESS_TOKEN_KEY, accessToken);

      const decodedIdToken = jwtDecode(idToken);
      const storedNonce = localStorage.getItem(OIDC_NONCE_KEY);

      if (decodedIdToken.nonce !== storedNonce) {
        console.error('Nonce mismatch!');
        logout();
        setLoading(false);
        return false;
      }
      localStorage.removeItem(OIDC_NONCE_KEY); // Clear nonce after validation

      setUserProfile(decodedIdToken);
      localStorage.setItem(USER_PROFILE_KEY, JSON.stringify(decodedIdToken));
      setIsAuthenticated(true);
      setLoading(false);
      return true;

    } catch (error) {
      console.error('Error handling OIDC callback:', error);
      logout();
      setLoading(false);
      return false;
    }
  };

  const logout = () => {
    localStorage.removeItem(ID_TOKEN_KEY);
    localStorage.removeItem(ACCESS_TOKEN_KEY);
    localStorage.removeItem(USER_PROFILE_KEY);
    localStorage.removeItem(OIDC_STATE_KEY); // Just in case
    localStorage.removeItem(OIDC_NONCE_KEY); // Just in case
    localStorage.removeItem(PKCE_CODE_VERIFIER_KEY); // Just in case
    setIsAuthenticated(false);
    setUserProfile(null);
    setLoading(false);
  };

  const getIdToken = () => localStorage.getItem(ID_TOKEN_KEY);
  const getAccessToken = () => localStorage.getItem(ACCESS_TOKEN_KEY);

  return (
    <AuthContext.Provider
      value={{
        isAuthenticated,
        userProfile,
        loading,
        login,
        logout,
        handleCallback,
        getIdToken,
        getAccessToken,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

