import React from 'react';
import { useAuth } from './AuthContext';

function Home() {
  const { isAuthenticated, userProfile, loading, login, logout } = useAuth();

  if (loading) {
    return <div style={{ textAlign: 'center', fontSize: '1.2em' }}>Loading authentication status...</div>;
  }

  return (
    <div>
      <h1 style={{ color: '#333' }}>React OIDC SPA</h1>
      {isAuthenticated ? (
        <div>
          <h2 style={{ color: '#007bff' }}>Welcome, {userProfile?.name || userProfile?.sub}!</h2>
          <p>You are successfully authenticated.</p>
          <button
            onClick={logout}
            style={{
              padding: '10px 20px',
              fontSize: '1em',
              backgroundColor: '#dc3545',
              color: 'white',
              border: 'none',
              borderRadius: '5px',
              cursor: 'pointer',
              marginTop: '10px',
            }}
          >
            Logout
          </button>
          <div style={{ marginTop: '20px', borderTop: '1px solid #eee', paddingTop: '15px' }}>
            <h3 style={{ color: '#555' }}>Your Profile Information (from ID Token)</h3>
            <pre style={{ backgroundColor: '#f8f9fa', padding: '15px', borderRadius: '5px', overflowX: 'auto' }}>
              {JSON.stringify(userProfile, null, 2)}
            </pre>
          </div>
        </div>
      ) : (
        <div>
          <p>You are not authenticated.</p>
          <button
            onClick={login}
            style={{
              padding: '10px 20px',
              fontSize: '1em',
              backgroundColor: '#28a745',
              color: 'white',
              border: 'none',
              borderRadius: '5px',
              cursor: 'pointer',
              marginTop: '10px',
            }}
          >
            Login with OpenID Connect
          </button>
          <p style={{ marginTop: '20px', fontSize: '0.9em', color: '#666' }}>
            This application uses the <a href="https://demo.duendesoftware.com" target="_blank" rel="noopener noreferrer">Duende IdentityServer Demo</a> as the OIDC provider for demonstration purposes.
          </p>
        </div>
      )}
    </div>
  );
}

export default Home;

// Callback.js
import React, { useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from './AuthContext';

function Callback() {
  const location = useLocation();
  const navigate = useNavigate();
  const { handleCallback } = useAuth();

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const code = params.get('code');
    const state = params.get('state');
    const error = params.get('error');
    const errorDescription = params.get('error_description');

    if (error) {
      console.error('OIDC Error:', error, errorDescription);
      navigate('/', { replace: true, state: { error: errorDescription || error } });
      return;
    }

    if (code && state) {
      handleCallback(code, state).then(success => {
        if (success) {
          navigate('/', { replace: true });
        } else {
          // handleCallback already logs errors, just redirect home
          navigate('/', { replace: true, state: { error: 'Authentication failed. Please try again.' } });
        }
      });
    } else {
      console.error('Callback URL is missing code or state parameters.');
      navigate('/', { replace: true, state: { error: 'Invalid callback. Missing parameters.' } });
    }
  }, [location, navigate, handleCallback]);

  return (
    <div style={{ textAlign: 'center', padding: '50px' }}>
      <h2 style={{ color: '#007bff' }}>Processing authentication...</h2>
      <p>Please wait while we log you in.</p>
    </div>
  );
}

export default Callback;

